Sub 'loadEmail'
For each order EmpCod, EmlTip, EmlCod Where EmpCod = &EmpCod where EmlTip = &EmlTip where EmlCod = &EmlCod &EmlAss = EmlAss &EmlDtaEms = EmlDtaEms &EmlDtaEnv = EmlDtaEnv &EmlHorEms = EmlHorEms &EmlHorEnv = EmlHorEnv &EmlSts = EmlSts &EmlPesCod = EmlPesCod &EmlTipEml = EmlTipEml &EmlSeqCod = EmlSeqCod &EmlFilCod = EmlFilCod &EmlObs = EmlObs &EmlMsg = EmlMsg &EmlQtdTen = EmlQtdTen &EmlSeqItmCod = EmlSeqItmCod &EmlPedPDF = EmlPedPDF &EmlPedExcell = EmlPedExcell &EmlPedImp = EmlPedImp &EmlPedPdfTip = EmlPedPdfTip &EmlEnvNFe = EmlEnvNFe
If EmlHTML.IsEmpty() Or EmlHTML.IsNull() &WWPMailTemplateBody = 'E-Mail antigo. Visualização indisponível.' Else &WWPMailTemplateBody = EmlHTML EndIf
exit EndFor
Do 'loadPessoa' Do 'loadEmlRemetente'
EndSub
Sub 'loadPessoa'
For each order EmpCod, PesCod where EmpCod = &EmpCod where PesCod = &EmlPesCod &PesCodRaz = PesCodRaz exit when none if &EmlPesCod = -1 &PesCodRaz = 'SUPORTE' else &PesCodRaz = 'CONTADOR' EndIf EndFor
EndSub
Sub 'loadEmlRemetente'
For each order EmpCod, EmpEmlCod, EmpEmlTip where EmpCod = &EmpCod where EmpEmlTip = &EmlTip &EmlRemetente = '(' + EmpEml.Trim() + ')' exit when none &EmlRemetente = ('Não localizado') EndFor
EndSub
